import { useState, useEffect } from "react";
import Navbar from "../components/Navbar";
import RecipeCard from "../components/RecipeCard";
import axios from "axios";

const API_BASE_URL = "http://localhost:8080/api";

export default function HomePage({ setPage, setSelectedRecipe }) {
  const [activeCategory, setActiveCategory] = useState("All Recipes");
  const [search, setSearch] = useState("");
  const [recipes, setRecipes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const CATEGORIES = [
    { name: "All Recipes", icon: "🍽️" },
    { name: "Grilled", icon: "🔥" },
    { name: "Vegetarian", icon: "🥗" },
    { name: "Seafood", icon: "🐟" },
    { name: "Italian", icon: "🍝" },
    { name: "Asian", icon: "🍣" },
  ];

  useEffect(() => {
    fetchRecipes();
  }, []);

  const fetchRecipes = async () => {
    try {
      setLoading(true);
      const response = await axios.get(`${API_BASE_URL}/recipes`);
      if (response.data.success) {
        setRecipes(response.data.data);
      }
    } catch (err) {
      console.error("Error fetching recipes:", err);
      setError("Failed to load recipes");
      setRecipes([]);
    } finally {
      setLoading(false);
    }
  };

  const filtered = recipes.filter(r => {
    const matchCat = activeCategory === "All Recipes" || r.tag === activeCategory;
    const matchSearch = !search || r.title.toLowerCase().includes(search.toLowerCase()) ||
      (r.chefInfo && r.chefInfo.name && r.chefInfo.name.toLowerCase().includes(search.toLowerCase())) ||
      (r.tag && r.tag.toLowerCase().includes(search.toLowerCase()));
    return matchCat && matchSearch;
  });

  return (
    <div style={{ minHeight: "100vh", background: "var(--bg)" }}>
      {/* Hero Section */}
      <section style={{ 
        background: "linear-gradient(135deg, var(--navy-deep) 0%, var(--navy) 100%)", 
        textAlign: "center", 
        padding: "100px 24px 140px", 
        position: "relative", 
        overflow: "hidden" 
      }}>
        {/* Decorative background element */}
        <div style={{ 
          position: "absolute", 
          top: "50%", 
          left: "50%", 
          transform: "translate(-50%, -50%)",
          width: "600px",
          height: "600px",
          background: "radial-gradient(circle, rgba(255, 49, 49, 0.1) 0%, transparent 70%)",
          pointerEvents: "none"
        }} />

        <div style={{ position: "relative", zIndex: 1 }}>
          <h1 style={{ 
            fontSize: "clamp(40px, 6vw, 64px)", 
            fontWeight: 900, 
            color: "#fff", 
            lineHeight: 1.1, 
            marginBottom: "20px",
            letterSpacing: "-1px"
          }}>
            Best recipes <br /> for your taste
          </h1>
          <p style={{ 
            color: "rgba(255, 255, 255, 0.6)", 
            fontSize: "16px", 
            maxWidth: "500px", 
            margin: "0 auto 40px", 
            lineHeight: 1.6, 
            fontWeight: 400 
          }}>
            Discover delicious recipes from talented chefs around the world. Cook with confidence and create amazing meals.
          </p>
          <div style={{ display: "flex", gap: "16px", justifyContent: "center" }}>
            <button className="btn-primary" onClick={() => setPage("signup")}>Get Started</button>
            <button className="btn-secondary" style={{ background: "rgba(255, 255, 255, 0.1)", color: "#fff", borderColor: "rgba(255, 255, 255, 0.2)" }} onClick={() => setPage("login")}>Sign In</button>
          </div>
        </div>
      </section>

      {/* Floating Search Bar */}
      <div style={{ 
        maxWidth: "900px", 
        margin: "-45px auto 60px", 
        position: "relative", 
        zIndex: 10,
        padding: "0 24px"
      }}>
        <div style={{ 
          background: "#fff", 
          borderRadius: "var(--radius-lg)", 
          boxShadow: "var(--shadow-lg)", 
          display: "flex", 
          alignItems: "center", 
          padding: "8px 12px",
          border: "1px solid var(--border-light)"
        }}>
          <div style={{ padding: "0 16px", color: "#94a3b8" }}>🔍</div>
          <input 
            style={{ 
              flex: 1, 
              border: "none", 
              outline: "none", 
              fontSize: "15px", 
              color: "var(--text-main)", 
              padding: "12px 0" 
            }}
            placeholder="Search recipes, chefs, or ingredients..." 
            value={search} 
            onChange={e => setSearch(e.target.value)} 
          />
          <button style={{ 
            background: "#f1f5f9", 
            border: "none", 
            padding: "10px 18px", 
            borderRadius: "var(--radius-md)",
            fontSize: "13px", 
            fontWeight: "600",
            color: "#4b5563",
            display: "flex",
            alignItems: "center",
            gap: "8px"
          }}>
            <span>≡</span> Filters
          </button>
        </div>
      </div>

      {/* Main Content */}
      <main style={{ maxWidth: "1200px", margin: "0 auto", padding: "0 24px 100px" }}>
        <div style={{ marginBottom: "48px" }}>
          <p style={{ 
            fontSize: "12px", 
            fontWeight: "700", 
            color: "var(--text-muted)", 
            letterSpacing: "1px", 
            textTransform: "uppercase", 
            marginBottom: "16px" 
          }}>
            Categories
          </p>
          <div style={{ display: "flex", gap: "12px", overflowX: "auto", paddingBottom: "10px", scrollbarWidth: "none" }}>
            {CATEGORIES.map(cat => (
              <button 
                key={cat.name} 
                onClick={() => setActiveCategory(cat.name)} 
                style={{
                  display: "flex", 
                  alignItems: "center", 
                  gap: "8px", 
                  padding: "10px 20px", 
                  borderRadius: "99px",
                  fontSize: "14px", 
                  fontWeight: "600", 
                  border: "1.5px solid",
                  borderColor: activeCategory === cat.name ? "var(--primary)" : "#e2e8f0",
                  background: activeCategory === cat.name ? "var(--primary)" : "#fff",
                  color: activeCategory === cat.name ? "#fff" : "#4b5563",
                  whiteSpace: "nowrap"
                }}
              >
                <span>{cat.icon}</span>
                {cat.name}
              </button>
            ))}
          </div>
        </div>

        <div style={{ display: "flex", alignItems: "baseline", gap: "16px", marginBottom: "32px" }}>
          <h2 style={{ fontSize: "32px", fontWeight: "800", color: "var(--text-main)" }}>All Recipes</h2>
          <span style={{ fontSize: "14px", color: "var(--text-muted)" }}>
            {loading ? "Discovering..." : error ? "Error" : `${filtered.length} amazing recipes`}
          </span>
        </div>

        {loading ? (
          <div style={{ textAlign: "center", padding: "80px 0" }}>
            <div style={{ fontSize: "18px", color: "var(--text-muted)" }}>Finding the best recipes for you...</div>
          </div>
        ) : error ? (
          <div style={{ textAlign: "center", padding: "80px 0", background: "#fff", borderRadius: "var(--radius-lg)", border: "1px solid var(--border-light)" }}>
            <div style={{ fontSize: "18px", color: "var(--primary)", marginBottom: "20px" }}>{error}</div>
            <button className="btn-primary" onClick={fetchRecipes}>Try Again</button>
          </div>
        ) : (
          <div style={{ 
            display: "grid", 
            gridTemplateColumns: "repeat(auto-fill, minmax(340px, 1fr))", 
            gap: "32px" 
          }}>
            {filtered.map(recipe => (
              <RecipeCard
                key={recipe._id}
                recipe={{
                  ...recipe,
                  id: recipe._id,
                  chef: recipe.chefInfo ? recipe.chefInfo.name : "Unknown Chef",
                  tagColor: catToColor(recipe.tag)
                }}
                onClick={r => { setSelectedRecipe(r); setPage("recipe-detail"); }}
              />
            ))}
          </div>
        )}
      </main>

      {/* Premium Footer */}
      <footer style={{ background: "var(--navy-deep)", padding: "100px 40px 40px", color: "#fff" }}>
        <div style={{ maxWidth: "1200px", margin: "0 auto" }}>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))", gap: "60px", marginBottom: "80px" }}>
            <div style={{ gridColumn: "span 2" }}>
              <div style={{ display: "flex", alignItems: "center", gap: "10px", marginBottom: "24px" }}>
                <div style={{ width: "32px", height: "32px", background: "var(--primary)", borderRadius: "8px", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "18px" }}>🍽</div>
                <span className="serif" style={{ fontSize: "24px", fontWeight: "700" }}>RecipeNest</span>
              </div>
              <p style={{ fontSize: "15px", color: "rgba(255,255,255,0.5)", lineHeight: "1.7", maxWidth: "300px" }}>
                Connecting food lovers with exceptional recipes from the world's most talented chefs. Join our community today.
              </p>
            </div>
            {[
              { title: "Platform", links: ["Explore", "Categories", "Trending", "Featured"] },
              { title: "Company", links: ["About Us", "Careers", "Contact", "Blog"] },
              { title: "Legal", links: ["Privacy Policy", "Terms of Service", "Cookie Policy"] }
            ].map(col => (
              <div key={col.title}>
                <h4 style={{ fontSize: "14px", fontWeight: "700", textTransform: "uppercase", letterSpacing: "1px", marginBottom: "24px", color: "#fff" }}>{col.title}</h4>
                <ul style={{ listStyle: "none" }}>
                  {col.links.map(link => (
                    <li key={link} style={{ marginBottom: "12px" }}>
                      <button style={{ background: "none", border: "none", color: "rgba(255,255,255,0.5)", fontSize: "14px", padding: 0 }}>{link}</button>
                    </li>
                  ))}
                </ul>
              </div>
            ))}
          </div>
          <div style={{ 
            display: "flex", 
            alignItems: "center", 
            justifyContent: "space-between", 
            borderTop: "1px solid rgba(255,255,255,0.1)", 
            paddingTop: "40px",
            fontSize: "13px",
            color: "rgba(255,255,255,0.3)"
          }}>
            <p>© 2024 RecipeNest Inc. All rights reserved.</p>
            <div style={{ display: "flex", gap: "20px" }}>
              <span>Instagram</span>
              <span>Twitter</span>
              <span>Facebook</span>
            </div>
          </div>
        </div>
      </footer>
    </div>
  );
}

function catToColor(cat) {
  const colors = {
    "Grilled": "#f59e0b",
    "Vegetarian": "#10b981",
    "Seafood": "#0ea5e9",
    "Italian": "#ef4444",
    "Asian": "#8b5cf6",
    "Desserts": "#ec4899"
  };
  return colors[cat] || "#64748b";
}
